import API from "./api";

// Lấy danh sách transfer
export const getTransfers = () =>
  API.get("/transfers");

// Tạo transfer
export const createTransfer = (data) =>
  API.post("/transfers", data);

// Reverse transfer
export const reverseTransfer = (id) =>
  API.post(`/transfers/${id}/reverse`);
